 129→const normalizeApiPath = (path = '') => (
 130→    String(path).startsWith('/api/')
 131→        ? String(path).slice(4)
 132→        : String(path)
 133→);
 134→
 135→const canonicalizeMetricsPath = (rawPath = '') => {
 136→    const normalized = normalizeApiPath(rawPath);
 137→    return normalized
 138→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 139→        .replace(/\/\d+(?=\/|$)/g, '/:id');
 140→};
