 142→const isPersonalizedGetRequest = (req) => {
 143→    if (req?.headers?.authorization) {
 144→        return true;
 145→    }
 146→
 147→    const userId = String(req?.query?.userId || '').trim();
 148→    const loggedInUserId = String(req?.query?.loggedInUserId || '').trim();
 149→    return Boolean(userId || loggedInUserId);
