 164→const normalizeWhitespace = (value) => String(value ?? '')
 165→    .replace(/\s+/g, ' ')
 166→    .trim();
 167→
 168→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 169→    const normalized = normalizeWhitespace(value);
 170→    if (!normalized) return '';
 171→    if (normalized.length <= maxLength) return normalized;
 172→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 173→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 174→};
