 184→const getRequestOrigin = (req) => {
 185→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 186→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 187→    const host = forwardedHost || req.get('host') || '';
 188→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 189→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 190→        ? forwardedProto
 191→        : requestProtocol === 'http' || requestProtocol === 'https'
 192→            ? requestProtocol
 193→            : 'https';
 194→
 195→    if (!host) {
 196→        return SITE_URL;
 197→    }
 198→
 199→    return `${protocol}://${host}`;
 200→};
