 202→const pickFirstNonEmptyString = (...values) => {
 203→    for (const value of values) {
 204→        if (typeof value === 'string') {
 205→            const trimmed = value.trim();
 206→            if (trimmed) return trimmed;
 207→        }
 208→    }
 209→    return '';
 210→};
