 212→const parseImageDimension = (value) => {
 213→    const parsed = Number(value);
 214→    if (!Number.isFinite(parsed)) return undefined;
 215→    return parsed;
 216→};
 217→
 218→const imageFromNodeLike = (nodeLike) => {
 219→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 220→
 221→    const src = pickFirstNonEmptyString(
 222→        nodeLike.src,
 223→        nodeLike.url,
 224→        nodeLike.image_url,
 225→        nodeLike.imageUrl,
 226→        nodeLike?.payload?.src,
 227→        nodeLike?.data?.src
 228→    );
 229→    if (!src) return null;
 230→
 231→    return {
 232→        src,
 233→        width: parseImageDimension(nodeLike.width),
 234→        height: parseImageDimension(nodeLike.height),
 235→    };
 236→};
