 278→const buildShareMetaFromJournal = (journal) => {
 279→    const lexicalData = extractFromLexical(journal?.content);
 280→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
 281→    const title = normalizedTitle || 'Untitled Post';
 282→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
 283→
 284→    let description = lexicalData.text || '';
 285→    if (!description) {
 286→        description = `Read "${title}" by ${authorName} on Iskryb`;
 287→    }
 288→
 289→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
 290→    let imageCandidateSource = 'fallback';
 291→    if (lexicalData.image?.src) {
 292→        imageCandidate = lexicalData.image.src;
 293→        imageCandidateSource = 'lexical';
 294→    } else if (journal?.users?.image_url) {
 295→        imageCandidate = journal.users.image_url;
 296→        imageCandidateSource = 'author_avatar';
 297→    }
 298→
 299→    return {
 300→        title,
 301→        normalizedTitle,
 302→        description: toPreviewText(description),
 303→        imageCandidate,
 304→        imageCandidateSource
