 308→const resolveAbsoluteHttpUrl = (rawUrl) => {
 309→    try {
 310→        const raw = String(rawUrl || '').trim();
 311→        if (!raw) return null;
 312→
 313→        const isSupabasePath =
 314→            raw.startsWith('/storage/v1/object/public/')
 315→            || raw.startsWith('storage/v1/object/public/');
 316→
 317→        const baseUrl = isSupabasePath && SUPABASE_URL
 318→            ? `${SUPABASE_URL}/`
 319→            : SITE_URL;
 320→
 321→        const parsed = new URL(raw, baseUrl);
 322→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 323→            return null;
 324→        }
 325→        return parsed.toString();
 326→    } catch {
 327→        return null;
 328→    }
 329→};
