 331→const isPrivateIpv4Address = (ip) => {
 332→    const parts = ip.split('.').map((part) => Number(part));
 333→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 334→        return true;
 335→    }
 336→
 337→    const [a, b] = parts;
 338→    if (a === 10 || a === 127 || a === 0) return true;
 339→    if (a === 169 && b === 254) return true;
 340→    if (a === 172 && b >= 16 && b <= 31) return true;
 341→    if (a === 192 && b === 168) return true;
 342→    return false;
 343→};
 344→
 345→const isPrivateIpv6Address = (ip) => {
 346→    const normalized = ip.toLowerCase();
 347→    return (
 348→        normalized === '::1' ||
 349→        normalized.startsWith('fc') ||
 350→        normalized.startsWith('fd') ||
 351→        normalized.startsWith('fe80:')
 352→    );
 353→};
 354→
 355→const isPrivateIpAddress = (ip) => {
 356→    const ipVersion = net.isIP(ip);
 357→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 358→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 359→    return true;
 360→};
