 429→const fetchRemoteImageBuffer = async (imageUrl) => {
 430→    const controller = new AbortController();
 431→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 432→
 433→    try {
 434→        const response = await fetch(imageUrl, {
 435→            method: 'GET',
 436→            redirect: 'follow',
 437→            signal: controller.signal,
 438→            headers: {
 439→                Accept: 'image/*,*/*;q=0.8',
 440→                'Accept-Encoding': 'identity',
 441→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 442→            },
 443→        });
 444→
 445→        if (!response.ok) {
 446→            throw new Error(`upstream image status ${response.status}`);
 447→        }
 448→
 449→        const finalUrl = response.url || imageUrl;
 450→        if (!isSafeRemoteImageUrl(finalUrl)) {
 451→            throw new Error('upstream redirected to unsafe url');
 452→        }
 453→
 454→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 455→        if (!contentType.startsWith('image/')) {
 456→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 457→        }
 458→        if (contentType.includes('image/svg')) {
 459→            throw new Error('svg images are not used for share previews');
 460→        }
 461→
 462→        const headerContentLength = Number(response.headers.get('content-length'));
 463→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 464→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 465→        }
 466→
 467→        const arrayBuffer = await response.arrayBuffer();
 468→        const buffer = Buffer.from(arrayBuffer);
 469→
 470→        if (!buffer.length) {
 471→            throw new Error('upstream image is empty');
 472→        }
 473→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 474→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 475→        }
 476→
 477→        return {
 478→            buffer,
 479→            contentType,
 480→            byteLength: buffer.length,
 481→            finalUrl,
 482→        };
 483→    } finally {
 484→        clearTimeout(timeout);
 485→    }
 486→};
