 639→// ── Profile share route: composite OG image for social media ──
 640→app.get('/share/u/:username/image', async (req, res) => {
 641→    const { username } = req.params;
 642→
 643→    // Serve from cache if available
 644→    const cached = getShareImageCached(`profile:${username}`);
 645→    if (cached) {
 646→        res.set('Content-Type', 'image/jpeg');
 647→        res.set('Cache-Control', 'public, max-age=3600');
 648→        return res.send(cached);
 649→    }
 650→
 651→    await ensureShareFonts();
 652→
 653→    try {
 654→        const result = await getUserByUsernameService(username);
 655→        const user = result?.userData?.[0];
 656→        if (!user) {
 657→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 658→        }
 659→
 660→        const displayName = normalizeWhitespace(user.name) || username;
 661→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 662→        const bio = toPreviewText(user.bio || '', 120);
 663→
 664→        // ── Fetch background image ──
 665→        let bgBuffer = null;
 666→        const bgStyle = user.background || {};
 667→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 668→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 669→            : null;
 670→        const bgImageUrl = bgImageMatch?.[1];
 671→
 672→        if (bgImageUrl) {
 673→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 674→            if (bgEval.ok && bgEval.resolvedUrl) {
 675→                try {
 676→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 677→                    bgBuffer = remote.buffer;
 678→                } catch { /* use fallback gradient */ }
 679→            }
 680→        }
 681→
 682→        // ── Base layer: background or dark gradient ──
 683→        let baseLayer;
 684→        if (bgBuffer) {
 685→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 686→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 687→                .toBuffer();
 688→        } else {
 689→            // Use profile's solid background color if available, otherwise dark fallback
 690→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 691→                ? bgStyle.background.trim()
 692→                : null;
 693→            const gradientSvg = solidColor
 694→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 695→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 696→                </svg>`
 697→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 698→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 699→                        <stop offset="0%" stop-color="#1a1a2e"/>
 700→                        <stop offset="100%" stop-color="#16213e"/>
 701→                    </linearGradient></defs>
 702→                    <rect width="100%" height="100%" fill="url(#g)"/>
 703→                </svg>`;
 704→            baseLayer = await sharp(Buffer.from(gradientSvg))
 705→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 706→                .png()
 707→                .toBuffer();
 708→        }
 709→
 710→        // ── Dark overlay for text readability ──
 711→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 712→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 713→        </svg>`;
 714→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 715→
 716→        // ── Circular avatar ──
 717→        let avatarComposite = null;
 718→        const avatarSize = 180;
 719→        const avatarUrl = user.image_url;
 720→        if (avatarUrl) {
 721→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 722→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 723→                try {
 724→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 725→                    const circleMask = Buffer.from(
 726→                        `<svg width="${avatarSize}" height="${avatarSize}">
 727→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 728→                        </svg>`
 729→                    );
 730→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 731→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 732→                        .png()
 733→                        .toBuffer();
 734→                    const circularAvatar = await sharp(resizedAvatar)
 735→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 736→                        .png()
 737→                        .toBuffer();
 738→                    avatarComposite = circularAvatar;
 739→                } catch { /* skip avatar */ }
 740→            }
 741→        }
 742→
 743→        // ── Compose all layers ──
 744→        const composites = [
 745→            { input: overlayBuffer, top: 0, left: 0 },
 746→        ];
 747→
 748→        if (avatarComposite) {
 749→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 750→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 751→        }
 752→
 753→        const finalImage = await sharp(baseLayer)
 754→            .composite(composites)
 755→            .jpeg({ quality: 82, mozjpeg: true })
 756→            .toBuffer();
 757→
 758→        setShareImageCached(`profile:${username}`, finalImage);
 759→        res.set('Content-Type', 'image/jpeg');
 760→        res.set('Cache-Control', 'public, max-age=3600');
 761→        return res.send(finalImage);
 762→    } catch (err) {
 763→        console.error('profile share image route error:', err?.message || err);
 764→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 765→    }
 766→});
