 830→app.get('/share/post/:journalId/image', async (req, res) => {
 831→    const { journalId } = req.params;
 832→    const debugMode = isShareImageDebugRequest(req);
 833→
 834→    // Serve from cache if available (skip for debug)
 835→    if (!debugMode) {
 836→        const cached = getShareImageCached(`post:${journalId}`);
 837→        if (cached) {
