  1→import supabase from "../services/supabase.js";
  2→import { asyncHandler } from "../utils/controllerHandler.js";
  3→import { recordPublishForStreak } from "../services/streakService.js";
  4→
  5→const OPINION_LIST_SELECT = `
  6→    id,
  7→    user_id,
  8→    parent_id,
  9→    opinion,
 10→    reply_count,
 11→    created_at,
 12→    users(name, id, user_email, image_url, badge)
 13→`;
 14→const MY_OPINION_SELECT = `
 15→    id,
 16→    user_id,
 17→    parent_id,
 18→    opinion,
 19→    reply_count,
 20→    created_at
 21→`;
 22→const USER_OPINION_SELECT = `
 23→    id,
 24→    user_id,
 25→    parent_id,
 26→    opinion,
 27→    reply_count,
 28→    created_at,
 29→    users(name, image_url, id, badge)
 30→`;
 31→
 32→const parseOpinionLimit = (raw) => {
 33→    const parsed = parseInt(raw);
 34→    if (isNaN(parsed) || parsed < 1 || parsed > 20) return null;
 35→    return parsed;
 36→};
 37→
 38→export const addOpinionController = asyncHandler(async (req, res) => {
 39→    const { opinion } = req.body;
 40→    if (!opinion || opinion.length > 280) {
 41→        return res.status(400).json({ error: 'no opinion or opinion is over 280 characters' });
 42→    }
 43→    const userId = req.userId;
 44→
 45→    const { data: insertedOpinion, error } = await supabase
 46→        .from('opinions')
 47→        .insert({ user_id: userId, opinion })
 48→        .select('id')
 49→        .single();
 50→
 51→    if (error) {
 52→        console.error('supabase error:', error.message);
 53→        return res.status(500).json({ error: 'supabase error' });
 54→    }
 55→
 56→    // Non-fatal: send @mention notifications
 57→    try {
 58→        const mentionMatches = opinion.match(/@([\w-]+)/g);
 59→        if (mentionMatches && mentionMatches.length > 0) {
 60→            const usernames = [...new Set(mentionMatches.map(m => m.slice(1)))].slice(0, 10);
 61→            const { data: mentionedUsers } = await supabase
 62→                .from('users')
 63→                .select('id, username')
 64→                .in('username', usernames);
 65→            if (mentionedUsers && mentionedUsers.length > 0) {
 66→                const notifs = mentionedUsers
 67→                    .filter(u => u.id !== userId)
 68→                    .map(u => ({
 69→                        sender_id: userId,
 70→                        receiver_id: u.id,
 71→                        opinion_id: insertedOpinion.id,
 72→                        type: 'mention',
 73→                        read: false,
 74→                    }));
 75→                if (notifs.length > 0) {
 76→                    await supabase.from('notification_opinions').insert(notifs);
 77→                }
 78→            }
 79→        }
 80→    } catch (mentionErr) {
 81→        console.error('non-fatal: opinion mention notification error', mentionErr?.message);
 82→    }
 83→
 84→    // Non-fatal: record publish for writing streak
 85→    try {
 86→        recordPublishForStreak(userId).catch(err =>
 87→            console.error('non-fatal: streak record failed:', err?.message || err)
 88→        );
 89→    } catch (streakErr) {
 90→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
 91→    }
 92→
 93→    return res.status(200).json({ message: 'success' });
 94→});
 95→
 96→export const getOpinionsController = asyncHandler(async (req, res) => {
 97→    const { before } = req.query;
 98→    const parsedLimit = parseOpinionLimit(req.query.limit);
 99→    if (parsedLimit == null) {
100→        return res.status(400).json({ error: 'limit should be number and it should be between 1 - 20' });
101→    }
102→
103→    let query = supabase
104→        .from('opinions')
105→        .select(OPINION_LIST_SELECT)
106→        .is('parent_id', null)
107→        .order('id', { ascending: false })
108→        .limit(parsedLimit + 1);
109→
110→    if (before) query = query.lt('id', before);
111→
112→    const { data: opinions, error } = await query;
113→    if (error) {
114→        console.error('supabase error:', error.message);
115→        return res.status(500).json({ error: 'supabase error on fetching opinions from database' });
116→    }
117→
118→    const hasMore = opinions?.length > parsedLimit;
119→    const slicedData = hasMore ? opinions.slice(0, parsedLimit) : opinions;
120→    return res.status(200).json({ data: slicedData, hasMore });
121→});
122→
123→export const getMyOpinionsController = asyncHandler(async (req, res) => {
124→    const { before } = req.query;
125→    const parsedLimit = parseOpinionLimit(req.query.limit);
126→    if (parsedLimit == null) {
127→        return res.status(400).json({ error: 'limit should be number and between 1 - 20' });
128→    }
129→
130→    let query = supabase
131→        .from('opinions')
132→        .select(MY_OPINION_SELECT)
